!function(){async function t(){try{let t=await fetch("/api/hydration/status");if(!t.ok)return;let i=await t.json();if(i.enabled&&i.isBehind){let t=i.goalMl-i.totalMl;await self.registration.showNotification("\uD83D\uDCA7 \xa1Hora de hidratarte!",{body:"Llevas ".concat(i.totalMl,"ml de ").concat(i.goalMl,"ml. Te faltan ").concat(t,"ml para tu objetivo."),icon:"/icon.svg",badge:"/icon.svg",tag:"hydration-reminder",renotify:!1,data:{url:"/"}})}}catch(t){}}self.addEventListener("message",i=>{i.data&&"CHECK_HYDRATION"===i.data.type&&t()}),self.addEventListener("notificationclick",t=>{"hydration-reminder"===t.notification.tag&&(t.notification.close(),t.waitUntil(self.clients.matchAll({type:"window"}).then(t=>{for(let i of t)if(i.url.includes("/")&&"focus"in i)return i.focus();if(self.clients.openWindow)return self.clients.openWindow("/")})))})}();